window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["n"]={"Nikodem": "<b>Nikodem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, także rzadkie nazwisko. Wywodzi się od słowa oznaczającego „ten, który zwycięża dla ludu” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Νικόδημος: νίκη „zwycięstwo” + δημος „lud”). To samo znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Nikodema\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodema</a>.", "Norbert": "<b>Norbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a>. Wywodzi się od słów <i>nord</i> – tj. północ i <i>beraht</i> – czyli błyszczeć, jaśnieć. Całość znaczy więc „ten, który dokonuje wielkich czynów na północy”, „sławny mąż z północy”.", "Natan": "<b>Natan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נָתָן, <i>dar, podarunek</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie. Imieniu Natan etymologicznie bliskie są imiona <a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Natanael</a> (<a href=\"https://pl.wikipedia.org/wiki/Natanael\" target=\"_blank\" rel=\"noopener noreferrer\">Nataniel</a>). <b>Natan</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/12_lipca\" target=\"_blank\" rel=\"noopener noreferrer\">12 lipca</a> oraz <a href=\"https://pl.wikipedia.org/wiki/25_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 grudnia</a>.", "Nazar": "<b>Nazar</b>, zwany też <b>okiem <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a></b> lub <b>okiem proroka</b> – <a href=\"https://pl.wikipedia.org/wiki/Amulet\" target=\"_blank\" rel=\"noopener noreferrer\">amulet</a> mający chronić przed „<a href=\"https://pl.wikipedia.org/wiki/Z%C5%82e_oko\" target=\"_blank\" rel=\"noopener noreferrer\">złym okiem</a>”. Nazwa nazar jest pochodzenia arabskiego i znaczy tyle co spojrzenie.", "Nataniel": "<b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Nika": "<b>Nika</b> – imię żeńskie o dyskusyjnym pochodzeniu. Może pochodzić od greckiego słowa <i>nike</i> oznaczającego zwycięstwo lub być zdrobnieniem od takich imion jak: <a href=\"https://pl.wikipedia.org/wiki/Monika\" target=\"_blank\" rel=\"noopener noreferrer\">Monika</a>, <a href=\"https://pl.wikipedia.org/wiki/Dominika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Dominika</a>, <a href=\"https://pl.wikipedia.org/wiki/Berenika_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Berenika</a> czy <a href=\"https://pl.wikipedia.org/wiki/Weronika\" target=\"_blank\" rel=\"noopener noreferrer\">Weronika</a>. ewentualnie od imion <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikoleta\" target=\"_blank\" rel=\"noopener noreferrer\">Nikoleta</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikolina\" target=\"_blank\" rel=\"noopener noreferrer\">Nikolina</a>, <a href=\"https://pl.wikipedia.org/wiki/Nikodema\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodema</a> itd.", "Nestor": "<b>Nestor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Istnieją liczni święci o tym imieniu.", "Nikoloz": "<b>Nikoloz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gruzi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">gruz.</a> ნიკოლოზი) – <a href=\"https://pl.wikipedia.org/wiki/Gruzja\" target=\"_blank\" rel=\"noopener noreferrer\">gruzińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>.", "Norman": "<b>Norman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>northman</i> oznaczającego „człowieka z północy” i odnoszącego się do <a href=\"https://pl.wikipedia.org/wiki/Wikingowie\" target=\"_blank\" rel=\"noopener noreferrer\">wikingów</a>.", "Nikola": "<b>Nikola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, współcześnie sprowadzony do języka polskiego żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Miko%C5%82aj\" target=\"_blank\" rel=\"noopener noreferrer\">Mikołaj</a>. Pochodzi od greckich słów <i>Nikos</i> – <i>zwycięstwo</i> i <i>laos</i> oznaczającego <i>ludzie</i>. Wśród imion nadawanych nowo narodzonym dzieciom, Nikola w 2017 r. zajmowała 26. miejsce w grupie imion żeńskich, co oznacza spadek o 16 miejsc od 2009 r., kiedy to zajmowała 10. miejsce w analogicznej grupie. W całej populacji Polek Nikola zajmowała w 2017 r. 73. miejsce (66 007 nadań). Imię zyskało jeszcze na popularności. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 78429 kobiet o imieniu Nikola nadanym jako imię pierwsze.", "Natanael": "<b>Natanael</b> (hebr. Bóg dał) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> hebrajskie, znaczeniowo przypomina takie imiona, jak greckie z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Teodor\" target=\"_blank\" rel=\"noopener noreferrer\">Teodor</a> czy polskie <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>.", "Napoleon": "<b>Napoleon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Neapol\" target=\"_blank\" rel=\"noopener noreferrer\">Neapolu</a>”.", "Nenad": "<b>Nenad</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie używane w <a href=\"https://pl.wikipedia.org/wiki/Chorwacja\" target=\"_blank\" rel=\"noopener noreferrer\">Chorwacji</a> i <a href=\"https://pl.wikipedia.org/wiki/Serbia\" target=\"_blank\" rel=\"noopener noreferrer\">Serbii</a>.", "Nizami": "<b>Nizami</b>, <b>Nezami Gandżawi</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;نظامی گنجوی&#8206;, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_azerbejd%C5%BCa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">azer.</a>&#160;<em>Nizami Gəncəvi</em>, właśc. Nizām ad-Dīn Abū Muhammad Ilyās ibn-Yusūf ibn-Zakī ibn-Muˤayyid Nizāmī Ganjavī; ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1141\" target=\"_blank\" rel=\"noopener noreferrer\">1141</a>, zm. ok. <a href=\"https://pl.wikipedia.org/wiki/1209\" target=\"_blank\" rel=\"noopener noreferrer\">1209</a>) – perski poeta pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Gand%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">Gandży</a> (dzisiejszy <a href=\"https://pl.wikipedia.org/wiki/Azerbejd%C5%BCan\" target=\"_blank\" rel=\"noopener noreferrer\">Azerbejdżan</a>), mieszkający przez całe życie w tym mieście i uważany za twórcę literatury perskiej.", "Nil": "<b>Nilus</b>, <b>Nil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, od gr. <i>neilos</i> – \"rzeka\". Istnieli liczni święci o tym imieniu.", "Nguyen": "Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nikon": "<b>Nikon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od greckiego <i>νικη (nike)</i>, co oznacza \"zwycięstwo\". Imię to stosunkowo największą popularnością cieszyło się u prawosławnych Słowian wschodnich. Nikon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/23_marca\" target=\"_blank\" rel=\"noopener noreferrer\">23 marca</a> i <a href=\"https://pl.wikipedia.org/wiki/26_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">26 listopada</a>.", "Nikifor": "<b>Nicefor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Od greckiego <i>Νικηφόρος (Nikiforos)</i>, czyli „niosący zwycięstwo”. Jego wschodniosłowiańską wersją jest <b>Nikifor</b>.", "Naftali": "<b>Neftali</b>, <b>Naftali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> נפתלי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Etymologię tego imienia (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>moja walka</i>, <i>wywalczony</i>) wywodzi się z <i><a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a></i> 30,8.", "Namir": "<b>Namir</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> (\"na\"; jedno ze znaczeń <i>na</i> nazywało kogoś, ze względu na kogo coś się działo\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło ono więc oznaczać \"ten, który pojawił się w czasie pokoju\" albo \"ten, dzięki któremu zapanuje pokój\".", "Nahum": "<b>Nahum</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od imienia <i>Nahum</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa „ten, który przynosi ukojenie”. Nosił je <a href=\"https://pl.wikipedia.org/wiki/Nahum_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">Nahum</a>, jeden z proroków mniejszych <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, który przepowiedział upadek <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> w spisanej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Nahuma\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Nahuma</a>.", "Nadar": "<b>Nadar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: <i>na</i> („na”) oraz <i>dar</i> („upominek, dar, ofiara”). Mogło ono oznaczać „ten, który jest darem”.", "Nepomucen": "<b>Nepomucen</b> - imię męskie pochodzenia łacińskiego. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Nepomucena\" target=\"_blank\" rel=\"noopener noreferrer\">Nepomucena</a>.", "Nikol": "<b>Pryzmat Nicola</b> (także <b>nikol</b>) – rodzaj <a href=\"https://pl.wikipedia.org/wiki/Polaryzator\" target=\"_blank\" rel=\"noopener noreferrer\">polaryzatora</a>. Polaryzacja światła zachodzi wskutek <a href=\"https://pl.wikipedia.org/wiki/Dw%C3%B3j%C5%82omno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dwójłomności</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Ca%C5%82kowite_wewn%C4%99trzne_odbicie\" target=\"_blank\" rel=\"noopener noreferrer\">całkowitego wewnętrznego odbicia</a> jednej ze składowych polaryzacyjnych światła. Nazwa pochodzi od wynalazcy, <a href=\"https://pl.wikipedia.org/wiki/Szkocja\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a> <a href=\"https://pl.wikipedia.org/wiki/Fizyka\" target=\"_blank\" rel=\"noopener noreferrer\">fizyka</a> i <a href=\"https://pl.wikipedia.org/wiki/Geologia\" target=\"_blank\" rel=\"noopener noreferrer\">geologa</a> <a href=\"https://pl.wikipedia.org/wiki/William_Nicol\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Nicola</a> żyjącego w na przełomie <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a>.", "Namaz": "Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Naoki": "<b>Naoki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおき, ナオキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Nikander": "<b>Nikander</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Nike</i> — (\"zwycięstwo\") i <i>andros</i> — (\"mężczyzna\"). Istnieje kilku świętych o tym imieniu.", "Nguyễn": "Nazwisko pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a>, gdzie jest pisane 阮 i wymawiane <i>Ruǎn</i> <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#91;</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_z_retrofleksj%C4%85_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ʐ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_wargowo-mi%C4%99kkopodniebienna\" target=\"_blank\" rel=\"noopener noreferrer\">w</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">à</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#93;</a>.", "Nikanor": "<b>Nikanor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, zaczerpnięte z <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>, z <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_deuterokanoniczne\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Machabejskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/Nikanor_(diakon)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikanor</a> był również jednym z pierwszych siedmiu <a href=\"https://pl.wikipedia.org/wiki/Diakon\" target=\"_blank\" rel=\"noopener noreferrer\">diakonów</a>. Imię jest formą oboczną imienia <a href=\"https://pl.wikipedia.org/wiki/Nikander_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikander</a>, pochodzi od greckiego słowa <i>nikao</i> = „zwyciężam”, czyli oznacza <i>zwycięzca</i>", "Niemir": "<b>Niemir</b>, <b>Niemirz</b>, <b>Niemierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>nie-</i> (negacja) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „tego, kto nie zna pokoju” albo powstało przez negację imion z członem <i>Mir-</i> (takich, jak <i><a href=\"https://pl.wikipedia.org/wiki/Mirogniew\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogniew</a></i> albo <i><a href=\"https://pl.wikipedia.org/wiki/Mirogod\" target=\"_blank\" rel=\"noopener noreferrer\">Mirogod</a></i>). Pisownia z kończowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>. W dawnych źródłach mazowieckich jako zamiennik tego imienia w formie <i><b>Niemierza</b></i> często pojawia się imię <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Erazm</a>.", "Nemezjusz": "<b>Nemezjusz</b>, <b>Nemezy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>némesis</i>, oznaczającego \"przydzielenie tego, co się komu należy\", które stało się w mitologii nazwą uosobienia sprawiedliwości (<a href=\"https://pl.wikipedia.org/wiki/Nemezis\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezis</a>). Istnieje kilku świętych patronów tego imienia.", "Nawoj": "<b>Nawoj</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Imię to składa się z dwóch członów: \"na\" (\"naj\") oraz \"woj\" (\"wojownik\"). Miało ono charakter życzący i miało sprawić, że ten, kto je nosi, będzie dobrym (najlepszym) wojownikiem. Jego żeńskim odpowiednikiem jest imię <a href=\"https://pl.wikipedia.org/wiki/Nawoja\" target=\"_blank\" rel=\"noopener noreferrer\">Nawoja</a>.", "Nel": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nicefor": "<b>Nicefor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Od greckiego <i>Νικηφόρος (Nikiforos)</i>, czyli „niosący zwycięstwo”. Jego wschodniosłowiańską wersją jest <b>Nikifor</b>.", "Nazariusz": "<b>Nazariusz</b>, <b>Nazary</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Wśród patronów tego imienia, <a href=\"https://pl.wikipedia.org/wiki/Nazariusz_i_Celsus\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazariusz</a>, męczennik z I lub III wieku.", "Nisan": "Kabaliści zwracają też uwagę na fakt, iż słowo <i>Pesach</i> może być rozłożone na dwa człony: <i>Pe</i> oraz <i>Sach</i>, co oznacza <i>usta mówią</i>.", "Nairi": "<b>Nairi</b> – <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">asyryjska</a> nazwa grupy plemion na terytorium starożytnego państwa <a href=\"https://pl.wikipedia.org/wiki/Urartu\" target=\"_blank\" rel=\"noopener noreferrer\">Urartu</a>. Określenie to funkcjonowało w XIII–XI wieku p.n.e. Niektóre obiekty geograficzne zachowały rdzeń „Nairi” także w późniejszych tekstach asyryjskich, na przykład <a href=\"https://pl.wikipedia.org/wiki/Wan_(jezioro)\" target=\"_blank\" rel=\"noopener noreferrer\">jezioro Wan</a> nazywane było „morzem krainy Nairi” – <i>tâmtu ša mât Nairi</i>. Niektórzy badacze pierwszej połowy XX wieku uznawali asyryjskie słowo „Nairi” za nazwę plemion <a href=\"https://pl.wikipedia.org/wiki/Huryci\" target=\"_blank\" rel=\"noopener noreferrer\">huryckich</a>. Tłumaczyłoby to pochodzenie Urartyjczyków od Hurytów. Badania lingwistyczne, prowadzone w drugiej połowie XX wieku, wykazały, że języki urartyjski i hurycki są ze sobą spokrewnione, co potwierdziło dotychczasową teorię. Niewielka liczba odkrytych źródeł pisanych nie pozwala na jednoznaczne określenie składu etnicznego plemion Nairi oraz zasięgu terytorialnego obszaru, który zamieszkiwały.", "Nuru": "<b>Nuru</b> jest formą <a href=\"https://pl.wikipedia.org/wiki/Masa%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">masażu</a> erotycznego z pełnym kontaktem z ciałem, podczas gdy zarówno masażysta lub masażystka, jak i klient są nadzy i pokryci żelem, tradycyjnie wykonanym na bazie <a href=\"https://pl.wikipedia.org/wiki/Makroglony\" target=\"_blank\" rel=\"noopener noreferrer\">wodorostów</a>. Słowo <i>nuru</i> (ぬる) pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka japońskiego</a> i oznacza „śliski”.", "Nand": "Uwaga: w terminologii angielskiej <i>disjunction</i> to polska <a href=\"https://pl.wikipedia.org/wiki/Alternatywa\" target=\"_blank\" rel=\"noopener noreferrer\">alternatywa</a>, odpowiednikiem polskiej dysjunkcji (Sheffera) jest natomiast <i>alternative denial</i>.", "Natalia": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Namysław": "<b>Namysław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które prawdopodobnie powstało poprzez \"poprawienie\" staropolskiego imienia <i>Namysł</i>, kiedy świadomość jego pochodzenia zatarła się i błędnie zostało ono uznane za imię kończące się członem <i>-sław</i> (zamiast <i>-mysł</i>).", "Nadia": "<b>Nadzieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, nawiązujące do jednej z trzech <a href=\"https://pl.wikipedia.org/wiki/Cnoty_teologalne\" target=\"_blank\" rel=\"noopener noreferrer\">cnót teologalnych</a>. <i>Nadia</i> jest zdrobnieniem od rosyjskiej wersji tego imienia – Nadieżdy. Wśród imion nadawanych nowo narodzonym dzieciom, Nadia w 2009 zajmowała 22. miejsce w grupie imion żeńskich.", "Nazary": "<b>Nazariasz</b>, <b>Nazary</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"oddany Bogu\". Wśród patronów tego imienia — męczennik Nazary (<a href=\"https://pl.wikipedia.org/wiki/I_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">I wiek</a>).", "Nagarjuna": "Inny <b>Nagardżuna</b> to tantryk, mistrz <a href=\"https://pl.wikipedia.org/wiki/Wad%C5%BCrajana\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmu Diamentowej Drogi</a> żyjący w <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII w.</a> Jego imię pochodzi od wężowych istot wodnych - <i><a href=\"https://pl.wikipedia.org/wiki/Nagowie\" target=\"_blank\" rel=\"noopener noreferrer\">nagów</a></i>, od których uzyskał m.in. sekretne nauki alchemiczne. W <a href=\"https://pl.wikipedia.org/wiki/Buddyzm_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie tybetańskim</a> znany przede wszystkim jako uczeń <a href=\"https://pl.wikipedia.org/wiki/Saraha\" target=\"_blank\" rel=\"noopener noreferrer\">Sarahy</a>, od którego otrzymał przekaz <a href=\"https://pl.wikipedia.org/wiki/Mahamudra\" target=\"_blank\" rel=\"noopener noreferrer\">mahamudry</a> - zwieńczenie buddyjskich nauk - który to następnie przekazał <a href=\"https://pl.wikipedia.org/wiki/Shavaripa\" target=\"_blank\" rel=\"noopener noreferrer\">Shavaripie</a>. Obecnie nauki te praktykowane są w szkole <a href=\"https://pl.wikipedia.org/wiki/Kagyu\" target=\"_blank\" rel=\"noopener noreferrer\">karma kagyu</a>.", "Nina": "<b>Nina</b> – imię żeńskie o niejasnej etymologii. Prawdopodobnie wywodzi się od imienia mitycznego założyciela <a href=\"https://pl.wikipedia.org/wiki/Niniwa\" target=\"_blank\" rel=\"noopener noreferrer\">Niniwy</a> i imperium asyryjskiego - Ninosa. W piśmiennictwie imię to występuje w formach: <i>Nina, Nino, Nunia, Nuna i Nonna</i>.", "Neftali": "Drugi syn <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakuba</a> i <a href=\"https://pl.wikipedia.org/wiki/Bilha\" target=\"_blank\" rel=\"noopener noreferrer\">Bilhy</a>, niewolnicy <a href=\"https://pl.wikipedia.org/wiki/Rachela\" target=\"_blank\" rel=\"noopener noreferrer\">Racheli</a>. Imię nadała mu Rachela na znak swojego zwycięstwa ze swoją siostrą <a href=\"https://pl.wikipedia.org/wiki/Lea_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Leą</a>. Protoplasta jednego z <a href=\"https://pl.wikipedia.org/wiki/Dwana%C5%9Bcie_Plemion_Izraela\" target=\"_blank\" rel=\"noopener noreferrer\">Dwunastu Plemion Izraela</a>.", "Niepełka": "<b>Niepełka</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>nie-</i> (negacja) i <i>-pełka</i> (\"pułk\"). Być może oznaczało \"tego, kto walczy samotnie\" albo powstało przez negację imion z członem <i>-pełk</i> (takich, jak <i><a href=\"https://pl.wikipedia.org/wiki/Przedpe%C5%82k\" target=\"_blank\" rel=\"noopener noreferrer\">Przedpełk</a></i> albo <i><a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99tope%C5%82k_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Świętopełk</a></i>).", "Nao": "<b>Nao</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なお, ナオ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn. Jest również używane jako skrót od imion <a href=\"https://pl.wikipedia.org/wiki/Naoko\" target=\"_blank\" rel=\"noopener noreferrer\">Naoko</a>, <a href=\"https://pl.wikipedia.org/wiki/Naoki\" target=\"_blank\" rel=\"noopener noreferrer\">Naoki</a>, Naomi, <a href=\"https://pl.wikipedia.org/wiki/Naoto\" target=\"_blank\" rel=\"noopener noreferrer\">Naoto</a> i itp.", "Naoto": "<b>Naoto</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおと, ナオト) – męskie popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Nam Cao": "<b>Nam Cao</b>, właśc. <b>Trần Hữu Tri</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/29_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">29 października</a> <a href=\"https://pl.wikipedia.org/wiki/1917\" target=\"_blank\" rel=\"noopener noreferrer\">1917</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/30_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">30 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1951\" target=\"_blank\" rel=\"noopener noreferrer\">1951</a>), imię chrzcielne <b>Giuse</b> – <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">wietnamski</a> pisarz.", "Nerio": "<b>Nerio</b> (także <b>Neriene</b> lub <b>Nerienis</b>) – w mitologii rzymskiej jedno z bóstw z grupy <i><a href=\"https://pl.wikipedia.org/wiki/Indigetes\" target=\"_blank\" rel=\"noopener noreferrer\">indigetes</a></i>, pomniejszych lokalnych bóstw o wyraźnie sprecyzowanych kompetencjach; Nerio może być bóstwem <a href=\"https://pl.wikipedia.org/wiki/Sabinowie\" target=\"_blank\" rel=\"noopener noreferrer\">sabińskiego</a> pochodzenia. Nerio była boginią kojarzoną ze sferą wojny, uważaną za personifikację odwagi w boju. Przedstawiano ją jako towarzyszkę lub małżonkę <a href=\"https://pl.wikipedia.org/wiki/Mars\" target=\"_blank\" rel=\"noopener noreferrer\">Marsa</a>, czasami utożsamiając z <a href=\"https://pl.wikipedia.org/wiki/Bellona_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Belloną</a> lub rzadziej <a href=\"https://pl.wikipedia.org/wiki/Minerwa\" target=\"_blank\" rel=\"noopener noreferrer\">Minerwą</a>.", "Nevan": "<b>Naomhán</b> – irlandzkie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie złożone ze słów <i>naomh</i> - \"święty\" oraz <i>àn</i> - zdrabniającego przyrostka. Imię to oznacza więc \"małego świętego\" - tym mianem określano też pomniejszych świętych w irlandzkim folklorze.", "Nobuo": "<b>Nobuo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のぶお, ノブオ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Nijo": "Przed wstąpieniem na tron nosił imię książę Morihito&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;守仁親王&#32;<i>Morihito-shinnō</i>). Był pierwszym synem cesarza <a href=\"https://pl.wikipedia.org/wiki/Go-Shirakawa\" target=\"_blank\" rel=\"noopener noreferrer\">Go-Shirakawa</a> i ojcem cesarza <a href=\"https://pl.wikipedia.org/wiki/Rokuj%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">Rokujō</a>.", "Nektariusz": "<b>Nektariusz</b> – imię greckie.", "Nat": "<b>Nat</b> (skr. od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>natural unit</i> „jednostka naturalna”; czasami także <b>nit</b> lub <b>nepit</b>, skr. od <i>Neper unit</i> – „jednostka <a href=\"https://pl.wikipedia.org/wiki/John_Napier\" target=\"_blank\" rel=\"noopener noreferrer\">Nepera</a>”) – <a href=\"https://pl.wikipedia.org/wiki/Logarytm\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmiczna</a> <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostka miary</a> <a href=\"https://pl.wikipedia.org/wiki/Ilo%C5%9B%C4%87_informacji\" target=\"_blank\" rel=\"noopener noreferrer\">ilości informacji</a>. 1 nat jest ilością <a href=\"https://pl.wikipedia.org/wiki/Informacja\" target=\"_blank\" rel=\"noopener noreferrer\">informacji</a> zawartą w <a href=\"https://pl.wikipedia.org/wiki/Komunikat\" target=\"_blank\" rel=\"noopener noreferrer\">wiadomości</a> o zajściu zdarzenia, którego <a href=\"https://pl.wikipedia.org/wiki/Prawdopodobie%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">prawdopodobieństwo</a> równe jest 1/<a href=\"https://pl.wikipedia.org/wiki/Podstawa_logarytmu_naturalnego\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>. Ilość informacji wyraża się w postaci <a href=\"https://pl.wikipedia.org/wiki/Logarytm_naturalny\" target=\"_blank\" rel=\"noopener noreferrer\">logarytmu naturalnego</a> liczby możliwych wariantów zdarzenia.", "Nadbor": "<b>Nadbor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Nad-</i> (\"nad\" lub człon pochodzący od innych wyrazów) i <i>-bor</i> („walczyć, zmagać się”). Być może oznaczało „tego, kto najlepiej walczy”.", "Nila": "<b>Nila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od gr. <i>neilos</i> - \"rzeka\". Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Nilus\" target=\"_blank\" rel=\"noopener noreferrer\">Nilus</a>.", "Nano": "<b>Nano</b> (<b>n</b>) (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr</a>. νάνος, <i>nanos</i> – „karzeł”) – <a href=\"https://pl.wikipedia.org/wiki/Przedrostek_SI\" target=\"_blank\" rel=\"noopener noreferrer\">przedrostek jednostki miary</a> oznaczający mnożnik 0,000&#160;000&#160;001 = 10 (jedna miliardowa).", "Noemi": "<b>Noemi</b> (hebr. Naomi, נָעֳמִי) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od hebrajskiego słowa oznaczającego „moja słodycz”.", "Nela": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Nun": "<b>Nun</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_egipska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii egipskiej</a> pramateria, pierwszy materialny przejaw bytu, Nun jest przede wszystkim żywiołem kosmicznym. Jest on stworzeniem morza, na którym unosi się ziemia. Prawdopodobnie Nun był najpierw personifikowany w <a href=\"https://pl.wikipedia.org/wiki/Hermopolis\" target=\"_blank\" rel=\"noopener noreferrer\">Hermopolis</a> jako bóstwo męskie. Niekiedy, jako jedno z bóstw Ósemki, miewał głowę żaby. Jako najstarszy z bogów, pochodzący jeszcze z czasów chaosu, nosił przydomki \"stary\" i <i>ojciec czasów</i>. Jako personifikacja wód kosmicznych miał za atrybut głowę byka.", "Noriaki": "<b>Noriaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のりあき, ノリアキ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Niklot": "Od jego syna, <a href=\"https://pl.wikipedia.org/wiki/Przybys%C5%82aw_(ksi%C4%85%C5%BC%C4%99_meklemburski)\" target=\"_blank\" rel=\"noopener noreferrer\">Przybysława</a> (<i>Pribislav</i>), wywodzi się <a href=\"https://pl.wikipedia.org/wiki/Dynastia_meklemburska\" target=\"_blank\" rel=\"noopener noreferrer\">dynastia książęca</a> panująca w <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckiej</a> <a href=\"https://pl.wikipedia.org/wiki/Meklemburgia\" target=\"_blank\" rel=\"noopener noreferrer\">Meklemburgii</a> do 1918 roku.", "Nang": "<b>Nang</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tajski\" target=\"_blank\" rel=\"noopener noreferrer\">język tajski</a>: หนัง) – tajski <a href=\"https://pl.wikipedia.org/wiki/Teatr_cieni\" target=\"_blank\" rel=\"noopener noreferrer\">teatr cieni</a>, oparty na lokalnej wersji <a href=\"https://pl.wikipedia.org/wiki/Ramajana\" target=\"_blank\" rel=\"noopener noreferrer\">Ramajany</a>. Do przedstawień wykorzystuje się specjalnie wykrojone skóry bawole. Przedstawieniu towarzyszy akompaniament muzyczny. Najstarsza zachowana wzmianka o tej formie sztuki pochodzi z XV w. Istnieją dwie regionalne odmiany: <i>nang yai</i> (zachodnia) oraz <i>nang talung</i> (południowa).", "Niecisław": "<b>Niecisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie nienotowane w źródłach staropolskich, prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> z początku <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> wieku. Złożone z członu \"Nieci-\" (\"wzniecać, wzbudzać\"), który jest niespotykany w staropolskich imionach dwuczłonowych, oraz członu \"-sław\" (\"sława\").", "Namika": "<b>Namika</b>, właśc. <b>Hanan Hamdi</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/7_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">7 września</a> <a href=\"https://pl.wikipedia.org/wiki/1991\" target=\"_blank\" rel=\"noopener noreferrer\">1991</a> we <a href=\"https://pl.wikipedia.org/wiki/Frankfurt_nad_Menem\" target=\"_blank\" rel=\"noopener noreferrer\">Frankfurcie nad Menem</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecka</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> <a href=\"https://pl.wikipedia.org/wiki/Maroko\" target=\"_blank\" rel=\"noopener noreferrer\">marokańskiego</a> pochodzenia.", "Nguyen Anh": "W 1777 jako najstarszy ocalały z rodu, został nominalnym władcą ogarniętego wojną domową południa Wietnamu. W 1802 po pokonaniu wszystkich przeciwników i zjednoczeniu całego kraju ogłosił się jedynym władcą Wietnamu i przyjął imię <b>Gia Long</b>.", "Nemi": "Miejsce, w którym leży miejscowość, uznawane było za święte już w <a href=\"https://pl.wikipedia.org/wiki/Epoka_br%C4%85zu\" target=\"_blank\" rel=\"noopener noreferrer\">epoce brązu</a>. Jego nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> słowa <i>nemus</i>, oznaczającego \"święty gaj\" i wiąże się z faktem, iż w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytności</a> rosnący tu las był jednym z najbardziej znanych miejsc kultu bogini <a href=\"https://pl.wikipedia.org/wiki/Diana_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Diany</a> i głównym sanktuarium <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zek_Laty%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Ligi Latyńskiej</a>. Szczególnym poważaniem otoczył to miejsce cesarz <a href=\"https://pl.wikipedia.org/wiki/Kaligula\" target=\"_blank\" rel=\"noopener noreferrer\">Kaligula</a>, który rozkazał odnowić istniejącą tu starą świątynię, a na jeziorze Nemi zbudować dwa wielkie <a href=\"https://pl.wikipedia.org/wiki/Statki_z_jeziora_Nemi\" target=\"_blank\" rel=\"noopener noreferrer\">statki</a>, pełniące funkcje kultowe.", "Ninos": "Imię Semiramida nadal jest popularne na obszarze Bliskiego Wschodu.", "Nadmir": "<b>Nadmir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Nad-</i> („nad” lub człon pochodzący od innych wyrazów) i <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „tego, kto przynosi prawdziwy pokój”.", "N": "<b>N</b> (<i>en</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>n</b>) – czternasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i osiemnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę przedniojęzykową nosową</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a>].", "Nepali": "Język nepalski jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a> w Nepalu. Zapisuje się go w alfabecie <a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a>; najstarsze zabytki piśmiennictwa w nepali pochodzą z XIV wieku.", "Natasza": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nadzieja": "<b>Nadzieja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, nawiązujące do jednej z trzech <a href=\"https://pl.wikipedia.org/wiki/Cnoty_teologalne\" target=\"_blank\" rel=\"noopener noreferrer\">cnót teologalnych</a>. <i>Nadia</i> jest zdrobnieniem od rosyjskiej wersji tego imienia – Nadieżdy. Wśród imion nadawanych nowo narodzonym dzieciom, Nadia w 2009 zajmowała 22. miejsce w grupie imion żeńskich.", "Nadiya": "<b>Nâdiya</b> (właściwie <b>Nadia Zighem</b>, ur. <a href=\"https://pl.wikipedia.org/wiki/19_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">19 czerwca</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a>) – <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuska</a> piosenkarka pochodzenia algiersko-włoskiego, wykonuje muzykę <a href=\"https://pl.wikipedia.org/wiki/Muzyka_pop\" target=\"_blank\" rel=\"noopener noreferrer\">pop</a> i <a href=\"https://pl.wikipedia.org/wiki/Rhythm_and_blues\" target=\"_blank\" rel=\"noopener noreferrer\">R&amp;B</a>. W młodości uprawiała zawodowo <a href=\"https://pl.wikipedia.org/wiki/Lekkoatletyka\" target=\"_blank\" rel=\"noopener noreferrer\">lekkoatletykę</a> – była mistrzynią Francji juniorek w <a href=\"https://pl.wikipedia.org/wiki/Bieg_na_800_metr%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">biegu na 800 metrów</a>.", "Nella": "<b>Nela</b> – imię żeńskie, powstałe jako usamodzielnione zdrobnienie imion z zakończeniem -<i>nela</i> lub podobnym, takich jak na przykład <a href=\"https://pl.wikipedia.org/wiki/Kornelia\" target=\"_blank\" rel=\"noopener noreferrer\">Kornelia</a> lub <a href=\"https://pl.wikipedia.org/wiki/Petronela\" target=\"_blank\" rel=\"noopener noreferrer\">Petronela</a>.", "Narcyza": "<b>Narcyza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Jest żeńskim odpowiednikiem męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Narcyz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Narcyz</a>.", "Nikolina": "<b>Nikolina</b> – imię żeńskie, powstałe poprzez zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, dokonane na gruncie języków romańskich.", "Nikoleta": "<b>Nikoleta</b>, <b>Nikoletta</b> – imię żeńskie pochodzenia włoskiego. Powstało od imienia <a href=\"https://pl.wikipedia.org/wiki/Nikola\" target=\"_blank\" rel=\"noopener noreferrer\">Nikola</a>, gdyż we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> i <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a> <i>Nicola</i>, <i>Nicolai</i> jest imieniem męskim, a jako żeński odpowiednik powstała <i>Nicolette</i>, <i>Nicoletta</i> ze względu na popularne we Włoszech końcówki imion <i>-etta</i>. Od Nikolety powstało imię <a href=\"https://pl.wikipedia.org/wiki/Koleta\" target=\"_blank\" rel=\"noopener noreferrer\">Koleta</a>, które jednak posiada w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> o wiele dłuższą tradycję niż Nikoleta.", "Neonila": "<b>Nunilona</b>, <b>Nunila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jego patronką jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Nunilona\" target=\"_blank\" rel=\"noopener noreferrer\">święta Nunilona</a>. Formą tego imienia, spotykaną w krajach wschodniosłowiańskich, jest <i>Neonila</i> lub <i>Neonilla</i>.", "Noelia": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nastazja": "<b>Nastazja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Pochodzi z języka greckiego, w którym oznacza osobę <a href=\"https://pl.wikipedia.org/wiki/Zmartwychwstanie\" target=\"_blank\" rel=\"noopener noreferrer\">zmartwychwstałą</a>, wskrzeszoną. W Polsce imię nadawane jest od XII wieku. Forma&#160;<i>Nastazja</i> jest w polszczyźnie rzadka, jednak, jak informują źródła, wystąpiła w dokumentach polskich już ok. roku 1265 (jako:&#160;<i>Nastazyja</i>).", "Nora": "<b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Nonna": "<b>Nonna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „dziewiąta” (dziewiąte dziecko w rodzinie) (analogicznie do <a href=\"https://pl.wikipedia.org/wiki/Oktawia\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawia</a> – „ósma”). Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Nonna_z_Nazjanzu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nonna</a>, matka św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Grzegorz_z_Nazjanzu\" target=\"_blank\" rel=\"noopener noreferrer\">Grzegorza z Nazjanzu</a>.", "Nawojka": "Prawdziwe imię tej studentki nie jest znane. Nie wymienia go jedyne źródło historyczne, którym jest autobiograficzne dzieło <i>Senatorium sive dialogus historicus</i> współczesnego jej Marcina ze Spisza&#65279;<a href=\"https://www.wikidata.org/wiki/Q1231085#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>. Upowszechnione imię Nawojka wynikało z błędnego domniemania polskiego historyka literatury, który w drugiej połowie XIX w. mylnie wiązał średniowieczną studentkę z autorką XVI-wiecznego „<a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_Nawojki\" target=\"_blank\" rel=\"noopener noreferrer\">Modlitewnika Nawojki</a>”. Domniemane imię przylgnęło do postaci najwcześniejszej studentki i weszło na stałe do legend Krakowa i Uniwersytetu Jagiellońskiego.", "Nicolette": "<b>Nicolette</b>, właściwie <b>Nicolette Love Suwoton</b> (ur. 1964 w <a href=\"https://pl.wikipedia.org/wiki/Glasgow\" target=\"_blank\" rel=\"noopener noreferrer\">Glasgow</a>) – szkocka piosenkarka, kompozytorka i DJ-ka <a href=\"https://pl.wikipedia.org/wiki/Nigeria\" target=\"_blank\" rel=\"noopener noreferrer\">nigeryjskiego</a> pochodzenia, wykonawczyni muzyki elektronicznej z kręgu <a href=\"https://pl.wikipedia.org/wiki/Ambient_techno\" target=\"_blank\" rel=\"noopener noreferrer\">ambient techno</a>, <a href=\"https://pl.wikipedia.org/wiki/Techno\" target=\"_blank\" rel=\"noopener noreferrer\">techno</a> i <a href=\"https://pl.wikipedia.org/wiki/Trip_hop\" target=\"_blank\" rel=\"noopener noreferrer\">trip hop</a>. Nagrała trzy albumy studyjne i jeden DJ mix.", "Norma": "<b>Norma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie stworzone przez <a href=\"https://pl.wikipedia.org/wiki/Felice_Romani\" target=\"_blank\" rel=\"noopener noreferrer\">Felice Romaniego</a>, <a href=\"https://pl.wikipedia.org/wiki/Libretto\" target=\"_blank\" rel=\"noopener noreferrer\">librecistę</a> <i><a href=\"https://pl.wikipedia.org/wiki/Norma_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Normy</a></i> <a href=\"https://pl.wikipedia.org/wiki/Vincenzo_Bellini\" target=\"_blank\" rel=\"noopener noreferrer\">Belliniego</a>, dla tytułowej bohaterki tej opery, prawdopodobnie w związku z <a href=\"https://pl.wikipedia.org/wiki/Norma\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim znaczeniem tego słowa</a> – reguła, zasada. Stosowane także jako żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Norman_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Norman</a>.", "Nga": "<b>Nga</b> (ڠ) – litera rozszerzonego <a href=\"https://pl.wikipedia.org/wiki/Alfabet_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu arabskiego</a>. Wykorzystywana jest w <a href=\"https://pl.wikipedia.org/wiki/Pismo_jawi\" target=\"_blank\" rel=\"noopener noreferrer\">piśmie jawi</a>, na którym oparty jest jeden z alfabetów języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_malajski\" target=\"_blank\" rel=\"noopener noreferrer\">malajskiego</a>. Używana jest do oznaczenia dźwięku [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ŋ</a>], tj. <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_tylnoj%C4%99zykowo-mi%C4%99kkopodniebienna_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoski nosowej tylnojęzykowo-miękkopodniebiennej dźwięcznej</a>.", "Niamh": "<b>Niamh</b>, inaczej <b>Niam Złotowłosa</b> – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_celtycka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii celtyckiej</a> była córką <a href=\"https://pl.wikipedia.org/wiki/Manannan\" target=\"_blank\" rel=\"noopener noreferrer\">Manannan mac Lira</a> i królowej <a href=\"https://pl.wikipedia.org/wiki/T%C3%ADr_na_n%C3%93g\" target=\"_blank\" rel=\"noopener noreferrer\">Tír na nÓg</a>. Jej imię oznacza \"Piękna\".", "Natalja": "<b>Natalia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em><a href=\"https://pl.wikipedia.org/wiki/Dies_natalis\" target=\"_blank\" rel=\"noopener noreferrer\">Dies natalis</a> Domini</em>, tj. <i>w dniu urodzin <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Pana</a></i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie wywodzące się od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Natal_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Natalis</a>. W Polsce to imię jest poświadczane w formie Natalia w XIV wieku. Dawniej nadawane osobom urodzonym w dniach chrześcijańskich świąt <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCe_Narodzenie\" target=\"_blank\" rel=\"noopener noreferrer\">Bożego Narodzenia</a>. Patronką imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Adrian_i_Natalia_z_Nikomedii\" target=\"_blank\" rel=\"noopener noreferrer\">Natalia z Nikomedii</a>, męczennica.", "Nikodema": "<b>Nikodema</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nikodem\" target=\"_blank\" rel=\"noopener noreferrer\">Nikodem</a>, które jest złożone z wyrazów <i>níkē</i> (gr. „zwycięstwo”) i <i>dēmos</i> (gr. „lud”). Imię <b>Nikodema</b> nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1846\" target=\"_blank\" rel=\"noopener noreferrer\">1846</a> roku, zaś w rodzinach polskich poza ziemiami rdzennie polskimi co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1793\" target=\"_blank\" rel=\"noopener noreferrer\">1793</a> roku.", "Nawoja": "<b>Nawoja</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Nawoj\" target=\"_blank\" rel=\"noopener noreferrer\">Nawoj</a>. \"Na\" posiada liczne znaczenia, m.in. nazywające kogoś, ze względu na kogo dzieje się jakaś akcja&#8201;. W źródłach polskich poświadczone od XV wieku (1411 rok).", "Norberta": "<b>Norberta</b> – żeński odpowiednik starogermańskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Norbert\" target=\"_blank\" rel=\"noopener noreferrer\">Norbert</a>.", "Nikandra": "<b>Nikandra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów <i>Nike</i> - (\"zwycięstwo\") i <i>andros</i> - (\"lud\"). Odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Nikander_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Nikander</a>.", "Nena": "Przydomek „Nena” nadały jej hiszpańskie dzieci, z którymi w młodości spędziła wakacje w <a href=\"https://pl.wikipedia.org/wiki/Alicante\" target=\"_blank\" rel=\"noopener noreferrer\">Alicante</a> i które nie znały jej imienia, dlatego wołały do niej „niña” (dziewczynka).", "Noriko": "<b>Noriko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のりこ, ノリコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Naoko": "<b>Naoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なおこ, ナオコ) − <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, które jest czasami pisane <b>Nahoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なほこ, ナホコ).", "Nasturcja": "<b>Nasturcja</b> (<i>Tropaeolum</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Nasturcjowate\" target=\"_blank\" rel=\"noopener noreferrer\">nasturcjowatych</a> (<i>Tropaeolaceae</i>). Należy do niego ponad 80 gatunków pochodzących z <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Południowej</a> i <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Środkowej</a>, największe zróżnicowanie osiąga wzdłuż <a href=\"https://pl.wikipedia.org/wiki/Andy\" target=\"_blank\" rel=\"noopener noreferrer\">Andów</a> od Kolumbii po południowe <a href=\"https://pl.wikipedia.org/wiki/Chile\" target=\"_blank\" rel=\"noopener noreferrer\">Chile</a>. W naturze rośliny te zasiedlają wilgotne lasy, suche zarośla i górskie <a href=\"https://pl.wikipedia.org/wiki/Piarg\" target=\"_blank\" rel=\"noopener noreferrer\">piargi</a>. Nasturcja bulwiasta jest ważną rośliną spożywczą dla ludności Ameryki Południowej. Mięsiste owoce i pąki kwiatowe nasturcji większej zakonserwowane w słonej wodzie lub occie stosowane są jak przyprawa (przypominają <a href=\"https://pl.wikipedia.org/wiki/Kapary\" target=\"_blank\" rel=\"noopener noreferrer\">kapary</a>). Niektóre gatunki są uprawiane jako ozdobne, dotyczy to zwłaszcza: <a href=\"https://pl.wikipedia.org/wiki/Nasturcja_wi%C4%99ksza\" target=\"_blank\" rel=\"noopener noreferrer\">nasturcji większej</a>, mniejszej, <i>Tropaeolum peltophorum</i> i mieszańce między nimi. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> najczęściej w uprawie ogrodowej lub na balkonach.", "Nimfa": "<b>Nimfa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>νύμφη (nymphe)</i> – \"dziewczyna, narzeczona\". Patronką tego imienia w Kościele katolickim jest św. Nimfa, córka prefekta <a href=\"https://pl.wikipedia.org/wiki/Palermo\" target=\"_blank\" rel=\"noopener noreferrer\">Palermo</a> w czasach <a href=\"https://pl.wikipedia.org/wiki/Konstantyn_I_Wielki\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantyna Wielkiego</a>.", "Nanami": "<b>Nanami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ななみ, ナナミ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, jest używane także jako nazwisko.", "Nerina": "<b>Nerina</b> (<i>Nerine</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin z rodziny <a href=\"https://pl.wikipedia.org/wiki/Amarylkowate\" target=\"_blank\" rel=\"noopener noreferrer\">amarylkowatych</a>. Obejmuje 23 gatunków. Rośliny te występują w <a href=\"https://pl.wikipedia.org/wiki/Afryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Afryce Południowej</a>, na północy sięgając <a href=\"https://pl.wikipedia.org/wiki/Namibia\" target=\"_blank\" rel=\"noopener noreferrer\">Namibii</a>, <a href=\"https://pl.wikipedia.org/wiki/Botswana\" target=\"_blank\" rel=\"noopener noreferrer\">Botswany</a> i <a href=\"https://pl.wikipedia.org/wiki/Zimbabwe\" target=\"_blank\" rel=\"noopener noreferrer\">Zimbabwe</a>. Dwa gatunki zostały <a href=\"https://pl.wikipedia.org/wiki/Introdukcja\" target=\"_blank\" rel=\"noopener noreferrer\">introdukowane</a> do <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>: <i>Nerine sarniensis</i> do <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a>, <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Madera\" target=\"_blank\" rel=\"noopener noreferrer\">Maderze</a> i <a href=\"https://pl.wikipedia.org/wiki/Azory\" target=\"_blank\" rel=\"noopener noreferrer\">Azorach</a>, a nerina ogrodowa do Wielkiej Brytanii. Rosną na <a href=\"https://pl.wikipedia.org/wiki/Klif\" target=\"_blank\" rel=\"noopener noreferrer\">klifach</a>, skałach, piaskach i mokradłach i kwitną jesienią. Kilka gatunków i liczne mieszańce uprawiane są jako rośliny ozdobne. Z powodu łatwości z jaką rośliny te się krzyżują – oznaczanie roślin z tego rodzaju bywa kłopotliwe.", "Natsuki": "<b>Natsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつき, ナツキ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, częściej noszone przez kobiety niż przez mężczyzn, jest także używane jako nazwisko.", "Nemezja": "<b>Nemezja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imion: <a href=\"https://pl.wikipedia.org/wiki/Nemezjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezjusz</a> i <a href=\"https://pl.wikipedia.org/wiki/Nemezy\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezy</a>. Wywodzi się od słowa <i>némesis</i>, oznaczającego „przydzielenie tego, co się komu należy”, które stało się w mitologii nazwą uosobienia sprawiedliwości (<a href=\"https://pl.wikipedia.org/wiki/Nemezis\" target=\"_blank\" rel=\"noopener noreferrer\">Nemezis</a>).", "Nazaria": "<b>Nazaria</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Nazaret\" target=\"_blank\" rel=\"noopener noreferrer\">Nazaretu</a>\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Nazaria_Ignacia_March_Mesa\" target=\"_blank\" rel=\"noopener noreferrer\">św. Nazaria Ignacja March Mesa</a>.", "Nagisa": "<b>Nagisa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;渚, なぎさ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a>, noszone zarówno przez kobiety i mężczyzn.", "Nurbanu": "<b>Afife Nurbanu Sultan</b> (pełne imię <i>Haseki Afife Nûr-Banû Vâlide Sultân Aliyyetü'ş-Şân Hazretleri</i>; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_osma%C5%84skoturecki\" target=\"_blank\" rel=\"noopener noreferrer\">osmań.</a> نور بانو سلطان; (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1525\" target=\"_blank\" rel=\"noopener noreferrer\">1525</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/7_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">7 grudnia</a> <a href=\"https://pl.wikipedia.org/wiki/1583\" target=\"_blank\" rel=\"noopener noreferrer\">1583</a>) – <a href=\"https://pl.wikipedia.org/wiki/Haseki\" target=\"_blank\" rel=\"noopener noreferrer\">Haseki Sultan</a> jako ulubiona nałożnica, a później prawowita żona sułtana <a href=\"https://pl.wikipedia.org/wiki/Selim_II\" target=\"_blank\" rel=\"noopener noreferrer\">Selima II</a>, <a href=\"https://pl.wikipedia.org/wiki/Valide_Sultan\" target=\"_blank\" rel=\"noopener noreferrer\">Valide Sultan</a> oraz koregentka jako matka <a href=\"https://pl.wikipedia.org/wiki/Murad_III\" target=\"_blank\" rel=\"noopener noreferrer\">Murada III</a>.", "Natsumi": "<b>Natsumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつみ, ナツミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, używane jest też jako nazwisko.", "Nepomucena": "<b>Nepomucena</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nepomucen\" target=\"_blank\" rel=\"noopener noreferrer\">Nepomucen</a>.", "Nefertiti": "Pochodzenie Nefertiti nie jest jasne. Przedstawia się teorię, jakoby była księżniczką <a href=\"https://pl.wikipedia.org/wiki/Mitanni\" target=\"_blank\" rel=\"noopener noreferrer\">mitannijską</a> – co tłumaczyłoby jej imię, utożsamia się ją też z <a href=\"https://pl.wikipedia.org/wiki/Taduhepa\" target=\"_blank\" rel=\"noopener noreferrer\">Taduhepą</a>. Przyjmuje się także, że była córką doradcy dworu <a href=\"https://pl.wikipedia.org/wiki/Aj_(faraon)\" target=\"_blank\" rel=\"noopener noreferrer\">Aja</a>, który wstąpił na tron po śmierci <a href=\"https://pl.wikipedia.org/wiki/Tutanchamon\" target=\"_blank\" rel=\"noopener noreferrer\">Tutanchamona</a>.", "Natsuko": "<b>Natsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;なつこ, ナツコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Nobuko": "<b>Nobuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;のぶこ, ノブコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Nefretete": "Pochodzenie Nefertiti nie jest jasne. Przedstawia się teorię, jakoby była księżniczką <a href=\"https://pl.wikipedia.org/wiki/Mitanni\" target=\"_blank\" rel=\"noopener noreferrer\">mitannijską</a> – co tłumaczyłoby jej imię, utożsamia się ją też z <a href=\"https://pl.wikipedia.org/wiki/Taduhepa\" target=\"_blank\" rel=\"noopener noreferrer\">Taduhepą</a>. Przyjmuje się także, że była córką doradcy dworu <a href=\"https://pl.wikipedia.org/wiki/Aj_(faraon)\" target=\"_blank\" rel=\"noopener noreferrer\">Aja</a>, który wstąpił na tron po śmierci <a href=\"https://pl.wikipedia.org/wiki/Tutanchamon\" target=\"_blank\" rel=\"noopener noreferrer\">Tutanchamona</a>.", "Niceta": "<b>Niceta</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Nicetas\" target=\"_blank\" rel=\"noopener noreferrer\">Nicetas</a>. U Słowian zachodnich znana jest też inna forma tego imienia, <b>Nikita</b>, które jest imieniem zarówno żeńskim, jak i męskim.", "Nemezis": "<b>Nemezis</b> (także <b>Nemezys</b>; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Νέμεσις Némesis, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Nemesis</em>, <i>Rivalitas</i> ‘postanowienie’, ‘rozdająca to, co należne’) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogini</a> zemsty, sprawiedliwości i przeznaczenia. Nazywana kobietą bez winy i wstydu. Znana była także jako <b>Adrasteja</b> (gr. Ἀδράστεια <i>Adrásteia</i>, łac. <i>Adrastea</i> – 'nieunikniona'). Zsyłała na ludzi szczęście lub niepowodzenie, ścigała przestępców i decydowała o losie w zależności od zasług. Córka <a href=\"https://pl.wikipedia.org/wiki/Nyks\" target=\"_blank\" rel=\"noopener noreferrer\">Nyks</a> i <a href=\"https://pl.wikipedia.org/wiki/Ereb\" target=\"_blank\" rel=\"noopener noreferrer\">Ereba</a>, uważana za uosobienie gniewu <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bogów</a>. Ośrodkiem jej kultu było <a href=\"https://pl.wikipedia.org/wiki/Ramnus\" target=\"_blank\" rel=\"noopener noreferrer\">Ramnus</a> w <a href=\"https://pl.wikipedia.org/wiki/Attyka_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Attyce</a>, stąd była nazywana <b>Ramnuzją</b> (gr. Ῥαμνουσία <i>Rhamnusía</i>, łac. <i>Rhamnusia virgo</i>). Stała na straży równowagi świata wraz z <a href=\"https://pl.wikipedia.org/wiki/Erynie\" target=\"_blank\" rel=\"noopener noreferrer\">Eryniami</a>.", "Neilia": "<b>Neilia</b>, <b>tawulec</b> (<i>Neillia</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należący do rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a> (<i>Rosaceae</i>). W tradycyjnym ujęciu rodzaj obejmował 11 gatunków. Na początku XXI wieku zostały tu także włączone cztery gatunki wyróżniane dotąd jako osobny rodzaj tawulec <i>Stephanandra</i>, po tym jak okazało się, że są ściśle spokrewnione i nie ma między nimi znaczących różnic morfologicznych. Są to <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewy</a> występujące w naturze we wschodniej Azji: od <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>, <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a> i <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">Chin</a> po <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepal</a> i <a href=\"https://pl.wikipedia.org/wiki/Indonezja\" target=\"_blank\" rel=\"noopener noreferrer\">Indonezję</a>. Introdukowany i zdziczały Tawulec pogięty <i>N. inicisa</i> występuje w <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryce Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rośliny te zasiedlają lasy, górskie formacje zaroślowe i tereny skaliste.", "Nekane": "<b>Dolores</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hiszpańskiego wywodzące się od słowa <i>dolor</i> oznaczającego <i>ból</i>. W języku hiszpańskim używane w <i>María de los Dolores</i> – <a href=\"https://pl.wikipedia.org/wiki/Matka_Boska_Bolesna\" target=\"_blank\" rel=\"noopener noreferrer\">Matka Boska Bolesna</a>. Popularnym zdrobnieniem imienia Dolores jest Lola lub <a href=\"https://pl.wikipedia.org/wiki/Lolita_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lolita</a>.", "Nanako": "<b>Nanako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ななこ, ナナコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Nu": "<b>Ny</b> (<b>ni</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">st.gr.</a> <b>νῦ</b>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_nowogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">nw.gr.</a> <b>νι</b>, pisana <b>Νν</b>) – trzynasta <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca spółgłoskę nosową przedniojęzykowo-dziąsłową „n”. W <a href=\"https://pl.wikipedia.org/wiki/Grecki_system_liczbowy\" target=\"_blank\" rel=\"noopener noreferrer\">greckim systemie liczbowym</a> oznaczała liczbę <a href=\"https://pl.wikipedia.org/wiki/50_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">50</a>.", "Nimo": "<b>Nimo</b>, właśc. <b>Nima Yaghobi</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/25_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">25 grudnia</a> <a href=\"https://pl.wikipedia.org/wiki/1995\" target=\"_blank\" rel=\"noopener noreferrer\">1995</a> w <a href=\"https://pl.wikipedia.org/wiki/Karlsruhe\" target=\"_blank\" rel=\"noopener noreferrer\">Karlsruhe</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecki</a> <a href=\"https://pl.wikipedia.org/wiki/Rap\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">irańskiego</a>."};
